sql:
SELECT income 
FROM median_household_incomes 
WHERE state_id = 0 AND year = '2023';

SELECT state_name, population
FROM states
ORDER BY population DESC;

external_knowledge:
- 'somewhat elevated joblessness' refers to unemployment rates over 6.5%;
- 'relatively low conflict situations' refers to violent crime rates below 20;
- 'typical poverty levels and educational attainment levels' refer to the average poverty rate and high school graduation rate.

sql:
SELECT AVG(population_density) AS avg_population_density
FROM states
WHERE region = 'Northeast' AND population_density > (SELECT AVG(population_density) FROM states);

SELECT AVG(income) AS average_median_income
FROM median_household_incomes
WHERE year = '2023';

external_knowledge:
- 'sea of average population' refers to the average population value calculated across all states;
- 'floating above' means having a population greater than the average;
- 'towering presence' signifies states with a significant population compared to the average.

sql:
SELECT state_name, population
FROM states
WHERE population > (SELECT AVG(population) FROM states);

SELECT AVG(rate) AS average_poverty_rate
FROM poverty_rates
WHERE year = '2023';
